<h1>Valor dos pedidos mensais por equipa</h1><?php $labels=array_values(array_unique(array_column($chartData,'month'))); $teams=array_values(array_unique(array_column($chartData,'team'))); $datasets=[]; foreach($teams as $idx=>$team){$datasets[]=['label'=>$team,'data'=>array_map(function($m)use($chartData,$team){foreach($chartData as $r){if($r['month']===$m && $r['team']===$team)return(float)$r['total'];}return 0;},$labels),'backgroundColor'=>['#0d6efd','#20c997','#ffc107','#dc3545','#6f42c1'][$idx%5]];} ?><div style="height:430px"><canvas id="requestsChart"></canvas></div><script>window.chartPayload=<?= json_encode(['labels'=>$labels,'datasets'=>$datasets], JSON_UNESCAPED_UNICODE) ?>;</script>
